const source = items[0]?.json ?? {};
function positiveNumber(field, fallback) {
  const value = Number(source[field] ?? fallback);
  if (!Number.isFinite(value) || value < 0) throw new Error(`${field} must be a non-negative number`);
  return value;
}
let invoices; let simulateFailures;
try { invoices = typeof source.invoices === 'string' ? JSON.parse(source.invoices) : source.invoices; } catch { throw new Error('invoices must be valid JSON'); }
try { simulateFailures = typeof source.simulate_failures === 'string' ? JSON.parse(source.simulate_failures) : (source.simulate_failures ?? {}); } catch { throw new Error('simulate_failures must be valid JSON'); }
if (!Array.isArray(invoices)) throw new Error('invoices must be an array');
const config = {
  minimum_amount: positiveNumber('minimum_amount', 100),
  reminder_days: positiveNumber('reminder_days', 7),
  escalation_days: positiveNumber('escalation_days', 30),
  severe_escalation_days: positiveNumber('severe_escalation_days', 60),
  currency_default: source.currency_default || 'USD',
  finance_alert_channel: source.finance_alert_channel || '#finance-collections',
  simulate_source_status: source.simulate_source_status || 'success',
  simulate_failures: simulateFailures,
  run_id: `collections-${new Date().toISOString().slice(0, 10)}-${Date.now()}`,
  retry_policy: { max_attempts: 3, backoff: 'exponential', retry_on: ['429', '408', '5xx', 'network_timeout'] },
};
if (config.escalation_days < config.reminder_days) throw new Error('escalation_days must be greater than or equal to reminder_days');
if (config.severe_escalation_days < config.escalation_days) throw new Error('severe_escalation_days must be greater than or equal to escalation_days');
return [{ json: { config, raw_invoices: invoices } }];

const source = items[0]?.json ?? {};
const config = source.config;
const checkedAt = new Date().toISOString();
const status = config.simulate_source_status;
if (status === 'failed') {
  return [{ json: { ...source, invoices: [], billing_source_status: { source: 'billing', status: 'failed', checked_at: checkedAt, completed_at: new Date().toISOString(), source_timestamp: null, records_returned: 0, error: 'Simulated billing API unavailable', retry_policy: config.retry_policy } } }];
}
let invoices = source.raw_invoices ?? [];
if (status === 'empty') invoices = [];
if (status === 'partial') invoices = invoices.slice(0, Math.max(1, Math.ceil(invoices.length / 2)));
return [{ json: { ...source, invoices, billing_source_status: { source: 'billing', status: status === 'partial' ? 'partial' : (invoices.length ? 'success' : 'empty'), checked_at: checkedAt, completed_at: new Date().toISOString(), source_timestamp: checkedAt, records_returned: invoices.length, retry_policy: config.retry_policy, warning: status === 'partial' ? 'Billing source returned a partial data set' : undefined } } }];

const source = items[0]?.json ?? {};
const status = source.billing_source_status ?? {};
const alerts = [];
if (['failed', 'partial', 'empty'].includes(status.status)) {
  alerts.push({ alert_type: 'collections_billing_source_degraded', severity: status.status === 'failed' ? 'high' : 'medium', source: 'billing', status: status.status, message: status.error || status.warning || `Billing source returned ${status.status}`, checked_at: status.checked_at, recommended_action: status.status === 'failed' ? 'Check billing connector credentials, API availability and workflow-level error handling.' : 'Review source freshness and confirm invoice data completeness before acting on the summary.' });
}
return [{ json: { ...source, operations_alerts: alerts } }];

const source = items[0]?.json ?? {};
const config = source.config;
const invoices = Array.isArray(source.invoices) ? source.invoices : [];
const normalised = []; const excluded = [];
function bucket(days) { if (days >= 60) return '60+ days'; if (days >= 31) return '31-60 days'; if (days >= 15) return '15-30 days'; if (days >= 7) return '7-14 days'; return 'under-threshold'; }
for (const invoice of invoices) {
  const amount = Number(invoice.amount_due ?? 0); const days = Number(invoice.days_overdue ?? 0); const id = String(invoice.invoice_id ?? '').trim(); const reasons = [];
  if (!id) reasons.push('missing_invoice_id');
  if (!invoice.customer_name) reasons.push('missing_customer_name');
  if (!invoice.customer_email) reasons.push('missing_customer_email');
  if (!Number.isFinite(amount) || amount <= 0) reasons.push('invalid_amount_due');
  if (!Number.isFinite(days) || days < config.reminder_days) reasons.push('below_reminder_age');
  if (amount < config.minimum_amount) reasons.push('below_minimum_amount');
  if (invoice.written_off === true || invoice.status === 'written_off') reasons.push('written_off');
  if (reasons.length) { excluded.push({ invoice_id: id || 'unknown', customer_name: invoice.customer_name, reasons }); continue; }
  const escalation_level = days >= config.severe_escalation_days ? 'severe' : (days >= config.escalation_days ? 'standard' : 'none');
  const baseKey = `${id}:${days}:${amount}`;
  normalised.push({ invoice_id: id, account_id: invoice.account_id || id, customer_name: invoice.customer_name, customer_email: invoice.customer_email, owner_email: invoice.owner_email || 'unassigned@yourcompany.com', amount_due: amount, currency: invoice.currency || config.currency_default, days_overdue: days, bucket: bucket(days), escalation_level, invoice_url: invoice.invoice_url || null, last_reminder_sent_at: invoice.last_reminder_sent_at || null, idempotency_keys: { customer_reminder: `collections:${baseKey}:customer-reminder`, owner_notification: `collections:${baseKey}:owner-notification`, internal_log: `collections:${baseKey}:internal-log`, escalation: `collections:${baseKey}:escalation` } });
}
return [{ json: { ...source, eligible_invoices: normalised, excluded_invoices: excluded } }];

const source = items[0]?.json ?? {}; const failures = source.config?.simulate_failures ?? {}; const failList = new Set(failures.customer_reminders || []); const results = [];
for (const invoice of source.eligible_invoices ?? []) {
  const startedAt = new Date().toISOString();
  try { if (failList.has(invoice.invoice_id)) throw new Error('Simulated customer reminder failure');
    const subject = `Reminder: overdue invoice ${invoice.invoice_id}`;
    const body = [`Hello ${invoice.customer_name},`, '', `Our records show invoice ${invoice.invoice_id} for ${invoice.currency} ${invoice.amount_due.toLocaleString()} is ${invoice.days_overdue} days overdue.`, 'Please arrange payment when possible or contact us if there is a query with the invoice.', invoice.invoice_url ? `Invoice link: ${invoice.invoice_url}` : '', '', 'Thank you.'].filter(Boolean).join('\\n');
    results.push({ invoice_id: invoice.invoice_id, action: 'customer_reminder', status: 'prepared', idempotency_key: invoice.idempotency_keys.customer_reminder, to: invoice.customer_email, subject, body, started_at: startedAt, completed_at: new Date().toISOString(), note: 'Replace this payload with Email Send or transactional email provider node.' });
  } catch (error) { results.push({ invoice_id: invoice.invoice_id, action: 'customer_reminder', status: 'failed', idempotency_key: invoice.idempotency_keys.customer_reminder, error: error.message, started_at: startedAt, completed_at: new Date().toISOString() }); }
}
return [{ json: { ...source, customer_reminder_results: results } }];

const source = items[0]?.json ?? {}; const failures = source.config?.simulate_failures ?? {}; const failList = new Set(failures.owner_notifications || []); const results = [];
for (const invoice of source.eligible_invoices ?? []) { const startedAt = new Date().toISOString(); try { if (failList.has(invoice.invoice_id)) throw new Error('Simulated account-owner notification failure'); results.push({ invoice_id: invoice.invoice_id, action: 'owner_notification', status: 'prepared', idempotency_key: invoice.idempotency_keys.owner_notification, to: invoice.owner_email, channel: 'account_owner_dm_or_email', message: `${invoice.customer_name} has overdue invoice ${invoice.invoice_id} for ${invoice.currency} ${invoice.amount_due.toLocaleString()} (${invoice.days_overdue} days overdue). Escalation level: ${invoice.escalation_level}.`, started_at: startedAt, completed_at: new Date().toISOString() }); } catch (error) { results.push({ invoice_id: invoice.invoice_id, action: 'owner_notification', status: 'failed', idempotency_key: invoice.idempotency_keys.owner_notification, error: error.message, started_at: startedAt, completed_at: new Date().toISOString() }); } }
return [{ json: { ...source, owner_notification_results: results } }];

const source = items[0]?.json ?? {}; const failures = source.config?.simulate_failures ?? {}; const failList = new Set(failures.internal_logging || []); const results = [];
for (const invoice of source.eligible_invoices ?? []) { const startedAt = new Date().toISOString(); try { if (failList.has(invoice.invoice_id)) throw new Error('Simulated collections log write failure'); results.push({ invoice_id: invoice.invoice_id, action: 'internal_log', status: 'prepared', idempotency_key: invoice.idempotency_keys.internal_log, row: { logged_at: new Date().toISOString(), invoice_id: invoice.invoice_id, customer_name: invoice.customer_name, amount_due: invoice.amount_due, currency: invoice.currency, days_overdue: invoice.days_overdue, bucket: invoice.bucket, escalation_level: invoice.escalation_level, owner_email: invoice.owner_email }, started_at: startedAt, completed_at: new Date().toISOString() }); } catch (error) { results.push({ invoice_id: invoice.invoice_id, action: 'internal_log', status: 'failed', idempotency_key: invoice.idempotency_keys.internal_log, error: error.message, started_at: startedAt, completed_at: new Date().toISOString() }); } }
return [{ json: { ...source, internal_log_results: results } }];

const source = items[0]?.json ?? {}; const failures = source.config?.simulate_failures ?? {}; const failList = new Set(failures.escalations || []); const results = [];
for (const invoice of source.eligible_invoices ?? []) { const startedAt = new Date().toISOString(); try { if (invoice.escalation_level === 'none') { results.push({ invoice_id: invoice.invoice_id, action: 'escalation', status: 'skipped', reason: 'below_escalation_threshold', idempotency_key: invoice.idempotency_keys.escalation, started_at: startedAt, completed_at: new Date().toISOString() }); continue; } if (failList.has(invoice.invoice_id)) throw new Error('Simulated escalation failure'); results.push({ invoice_id: invoice.invoice_id, action: 'escalation', status: 'prepared', escalation_level: invoice.escalation_level, idempotency_key: invoice.idempotency_keys.escalation, finance_channel: source.config.finance_alert_channel, message: `${invoice.escalation_level.toUpperCase()} collections escalation: ${invoice.customer_name} / ${invoice.invoice_id}, ${invoice.currency} ${invoice.amount_due.toLocaleString()}, ${invoice.days_overdue} days overdue. Owner: ${invoice.owner_email}.`, recommended_next_step: invoice.escalation_level === 'severe' ? 'Finance lead review and account-owner call task.' : 'Account owner follow-up and billing-system note update.', started_at: startedAt, completed_at: new Date().toISOString() }); } catch (error) { results.push({ invoice_id: invoice.invoice_id, action: 'escalation', status: 'failed', escalation_level: invoice.escalation_level, idempotency_key: invoice.idempotency_keys.escalation, error: error.message, started_at: startedAt, completed_at: new Date().toISOString() }); } }
return [{ json: { ...source, escalation_results: results } }];

const source = items[0]?.json ?? {}; const prompts = [];
for (const invoice of source.eligible_invoices ?? []) { prompts.push({ invoice_id: invoice.invoice_id, status: 'prepared_optional_prompt', data_policy: 'Data-minimised account-level fields only; deterministic template remains the approved fallback.', endpoint_hint: 'localhost:5001/completions', body_shape: { prompt: '<generated prompt>', alias: 'general' }, prompt: ['Rewrite the following collections reminder to be polite, concise and professional.', 'Do not change the amount, invoice ID, payment status, escalation status or requested action.', '', `Customer: ${invoice.customer_name}`, `Invoice ID: ${invoice.invoice_id}`, `Amount due: ${invoice.currency} ${invoice.amount_due}`, `Days overdue: ${invoice.days_overdue}`, `Escalation level: ${invoice.escalation_level}`].join('\\n') }); }
return [{ json: { ...source, optional_llm_reminder_prompts: prompts, llm_usage: { enabled_in_template: false, role: 'wording_support_only', decision_authority: 'deterministic_rules' } } }];

const source = items[0]?.json ?? {}; const invoices = source.eligible_invoices ?? [];
const buckets = { '7-14 days': { count: 0, total: 0 }, '15-30 days': { count: 0, total: 0 }, '31-60 days': { count: 0, total: 0 }, '60+ days': { count: 0, total: 0 } };
for (const invoice of invoices) { if (!buckets[invoice.bucket]) buckets[invoice.bucket] = { count: 0, total: 0 }; buckets[invoice.bucket].count += 1; buckets[invoice.bucket].total += invoice.amount_due; }
const actionGroups = [...(source.customer_reminder_results ?? []), ...(source.owner_notification_results ?? []), ...(source.internal_log_results ?? []), ...(source.escalation_results ?? [])];
const failedActions = actionGroups.filter(r => r.status === 'failed'); const preparedEscalations = (source.escalation_results ?? []).filter(r => r.status === 'prepared');
const totalOverdue = invoices.reduce((sum, inv) => sum + inv.amount_due, 0); const currency = invoices[0]?.currency || source.config?.currency_default || 'USD';
const overall_status = source.billing_source_status?.status === 'failed' ? 'failed' : (failedActions.length || source.billing_source_status?.status === 'partial' ? 'partial_success' : 'success');
const lines = []; lines.push('# Daily Collections Summary'); lines.push(''); lines.push('## Overview'); lines.push(`- ${invoices.length} overdue invoices eligible for action.`); lines.push(`- Total overdue: ${currency} ${totalOverdue.toLocaleString()}.`); lines.push(`- ${preparedEscalations.length} invoices prepared for escalation.`); lines.push(`- Overall workflow status: ${overall_status}.`); if ((source.operations_alerts ?? []).length) lines.push(`- Source warnings: ${(source.operations_alerts ?? []).map(a => `${a.source}:${a.status}`).join(', ')}.`); lines.push(''); lines.push('## Buckets'); for (const [name, data] of Object.entries(buckets)) lines.push(`- ${name}: ${data.count} invoices (${currency} ${data.total.toLocaleString()})`); lines.push(''); lines.push('## Newly escalated'); if (!preparedEscalations.length) { lines.push('- None.'); } else { preparedEscalations.forEach((result, index) => { const invoice = invoices.find(inv => inv.invoice_id === result.invoice_id); lines.push(`${index + 1}. **${invoice?.customer_name ?? result.invoice_id} – ${result.invoice_id}**`); lines.push(`   - Amount: ${invoice?.currency ?? currency} ${(invoice?.amount_due ?? 0).toLocaleString()}`); lines.push(`   - Days overdue: ${invoice?.days_overdue ?? 'unknown'}`); lines.push(`   - Owner: ${invoice?.owner_email ?? 'unknown'}`); lines.push(`   - Action: ${result.recommended_next_step}`); }); }
if (failedActions.length) { lines.push(''); lines.push('## Action failures'); failedActions.forEach(result => lines.push(`- ${result.invoice_id} / ${result.action}: ${result.error}`)); }
const summary_markdown = lines.join('\\n');
return [{ json: { ...source, collections_summary: { overall_status, invoice_count: invoices.length, total_overdue: totalOverdue, currency, buckets, escalated_count: preparedEscalations.length, failed_actions: failedActions }, summary_markdown } }];

const source = items[0]?.json ?? {};
const auditRecord = { audit_type: 'invoice_collections_run', audit_id: source.config?.run_id, logged_at: new Date().toISOString(), billing_source_status: source.billing_source_status, operations_alerts: source.operations_alerts ?? [], collections_summary: source.collections_summary, eligible_invoices: source.eligible_invoices, excluded_invoices: source.excluded_invoices, customer_reminder_results: source.customer_reminder_results, owner_notification_results: source.owner_notification_results, internal_log_results: source.internal_log_results, escalation_results: source.escalation_results, finance_notification: source.finance_notification, llm_usage: source.llm_usage };
return [{ json: { ...source, audit_record: auditRecord, audit_status: 'ready_for_durable_store' } }];
